const inputData = $input.first().json.body || $input.first().json;
const poses = inputData.poses || ['P1', 'P2', 'P3-A', 'P4', 'P5', 'P6-A'];
const orientations = inputData.orientations || ['16:9'];
const batch_name = inputData.batch_name || 'default';

// img2img edit prompts — repose the existing character, don't describe from scratch
const posePrompts = {
  'P1': {
    name: 'The Watch',
    refImage: 'tyroneFullBody_frontal.jpg',
    '16:9': 'Repose this character sitting upright in 3/4 angle, looking off-frame to the right. Composed, dignified, alert. Place him in a dark urban environment with a single rust-orange sodium vapor light from upper left. Dark steel background. Heavy vignette. Film grain 20%. Cinematic Roger Deakins lighting. Keep the character\'s exact appearance, clothing, and features identical. 16:9 widescreen.',
    '9:16': 'Portrait orientation 9:16. Vertical composition, subject in upper-center. Repose this character sitting upright in 3/4 angle, looking off-frame to the right. Composed, dignified, alert. Place him in a dark urban environment with a single rust-orange sodium vapor light from upper left. Dark steel background. Heavy vignette. Film grain 20%. Cinematic Roger Deakins lighting. Keep the character\'s exact appearance, clothing, and features identical. 9:16 vertical.'
  },
  'P2': {
    name: 'The Guard',
    refImage: 'tyroneFullBody_frontal.jpg',
    '16:9': 'Repose this character standing and facing the camera directly, shot from slightly below eye level. Powerful upright posture. Dark steel background with harsh overhead light casting dramatic downward shadows. Heavy vignette. Film grain 20%. Cinematic. Keep the character\'s exact appearance, clothing, and features identical. 16:9 widescreen.',
    '9:16': 'Portrait orientation 9:16. Vertical composition, subject in upper-center. Repose this character standing and facing the camera directly, shot from slightly below eye level. Powerful upright posture. Dark steel background with harsh overhead light casting dramatic downward shadows. Heavy vignette. Film grain 20%. Cinematic. Keep the character\'s exact appearance, clothing, and features identical. 9:16 vertical.'
  },
  'P3-A': {
    name: 'The Companion — Journal and Radio',
    refImage: 'tyroneFullBody_frontal.jpg',
    '16:9': 'Repose this character lying on his side on a dark concrete floor beside a weathered leather journal and a hand-crank emergency radio. Head up, resting on one front paw. Eyes open, alert. Single dramatic overhead light from upper left. Rust-orange warmth. Dark steel background. Film grain 20%. Cinematic. Keep the character\'s exact appearance, clothing, and features identical. 16:9 widescreen.',
    '9:16': 'Portrait orientation 9:16. Vertical composition, subject in upper-center. Repose this character lying on his side on a dark concrete floor beside a weathered leather journal and a hand-crank emergency radio. Head up, resting on one front paw. Eyes open, alert. Single dramatic overhead light from upper left. Rust-orange warmth. Dark steel background. Film grain 20%. Cinematic. Keep the character\'s exact appearance, clothing, and features identical. 9:16 vertical.'
  },
  'P4': {
    name: 'The Silhouette',
    refImage: 'tyroneFullBody_frontal.jpg',
    '16:9': 'Transform this into a silhouette scene: the character sitting at the edge of an urban rooftop overlooking city lights below. Night. Backlit so only the silhouette and rim light are visible. City sprawl in rust-orange and ash gray tones below. Atmospheric fog. Film grain 22%. Cinematic. Keep the character\'s overall shape and clothing recognizable in silhouette. 16:9 widescreen.',
    '9:16': 'Portrait orientation 9:16. Vertical composition, subject in upper-center. Transform this into a silhouette scene: the character sitting at the edge of an urban rooftop overlooking city lights below. Night. Backlit so only the silhouette and rim light are visible. City sprawl in rust-orange and ash gray tones below. Atmospheric fog. Film grain 22%. Cinematic. Keep the character\'s overall shape and clothing recognizable in silhouette. 9:16 vertical.'
  },
  'P5': {
    name: 'The Close',
    refImage: 'tyrone_redNose_headshot.jpg',
    '16:9': 'Create an extreme close-up of this character\'s face. Show one amber eye fully visible as the focal anchor, the scar across left brow, and the edge of coveralls at bottom. Shallow depth of field f/1.4. Dark steel background. Rust-orange light from right creating catchlight in the eye. Film grain 20%. Intimate and dramatic. Keep the character\'s exact features identical. 16:9 widescreen.',
    '9:16': 'Portrait orientation 9:16. Vertical composition, subject in upper-center. Create an extreme close-up of this character\'s face. Show one amber eye fully visible as the focal anchor, the scar across left brow, and the edge of coveralls at bottom. Shallow depth of field f/1.4. Dark steel background. Rust-orange light from right creating catchlight in the eye. Film grain 20%. Intimate and dramatic. Keep the character\'s exact features identical. 9:16 vertical.'
  },
  'P6-A': {
    name: 'The Aftermath — Empty Street',
    refImage: 'tyroneFullBody_frontal.jpg',
    '16:9': 'Repose this character walking through an empty urban street at night, mid-stride. Wet asphalt reflecting sodium vapor streetlights. Fog in background. No other figures present. 3/4 angle from front-left. Single dominant rust-orange light from streetlight above-right. Film grain 22%. Cinematic. Keep the character\'s exact appearance, clothing, and features identical. 16:9 widescreen.',
    '9:16': 'Portrait orientation 9:16. Vertical composition, subject in upper-center. Repose this character walking through an empty urban street at night, mid-stride. Wet asphalt reflecting sodium vapor streetlights. Fog in background. No other figures present. 3/4 angle from front-left. Single dominant rust-orange light from streetlight above-right. Film grain 22%. Cinematic. Keep the character\'s exact appearance, clothing, and features identical. 9:16 vertical.'
  }
};

// Style-only negatives (no character description negatives needed for img2img)
const negativePrompt = 'bright colors, neon, saturated, cheerful, suburban, clean corporate, stock photo, 3D render, watermark, text, logo, photorealistic photograph';

// Reference image Drive file IDs (uploaded via upload_canonical_images.py 2026-02-12)
const refImageDriveIds = {
  'tyroneFullBody_frontal.jpg': '1hesQCwGlHw1pqpxK5LlDmSNpVmkcJrEd',
  'tyrone_redNose_headshot.jpg': '1JGzUAlO1p0IumXiuHSCLJe77V9SO8kVd',
  'tyroneFullBody_quarterTurn.jpg': '1opAGD5SPmFdYwrwzFCMPta8JpwXTBxJB',
  'tyroneFullBody_hisLeftSide.jpg': '1cavcWSd4aX_eau6B11fmBMO7oRXUMpgy',
  'tyroneFullBody_hisRightSide.jpg': '1xPAu86eDcv72qOmKHsEgZpkBF1jPTCMk',
};

// Aspect ratio mapping for Gemini imageConfig
const aspectRatioMap = {
  '16:9': '16:9',
  '9:16': '9:16',
  '1:1': '1:1',
};

const items = [];

for (const pose_id of poses) {
  for (const orientation of orientations) {
    const poseData = posePrompts[pose_id];
    if (!poseData) continue;
    const prompt_text = poseData[orientation];
    if (!prompt_text) continue;

    const refImageName = poseData.refImage;
    const refImageDriveId = refImageDriveIds[refImageName] || refImageDriveIds['tyroneFullBody_frontal.jpg'];

    items.push({
      json: {
        pose_id,
        pose_name: poseData.name,
        orientation,
        aspect_ratio: aspectRatioMap[orientation] || '16:9',
        prompt_text,
        negative_prompt: negativePrompt,
        ref_image_name: refImageName,
        ref_image_drive_id: refImageDriveId,
        batch_name,
        timestamp: Date.now()
      }
    });
  }
}

return items;

// Build Gemini img2img request payload with reference image + edit prompt
const poseData = $('SplitInBatches').first().json;
const binaryData = $('Download Reference Image').first().binary.data;

// Get the base64 image data from the downloaded reference
const imageBase64 = binaryData.data;
const imageMimeType = binaryData.mimeType || 'image/jpeg';

const payload = {
  contents: [{
    parts: [
      {
        text: `${poseData.prompt_text}\n\nDo NOT include: ${poseData.negative_prompt}`
      },
      {
        inline_data: {
          mime_type: imageMimeType,
          data: imageBase64
        }
      }
    ]
  }],
  generationConfig: {
    responseModalities: ['TEXT', 'IMAGE'],
    imageConfig: {
      aspectRatio: poseData.aspect_ratio || '16:9'
    }
  }
};

return [{
  json: {
    ...poseData,
    gemini_payload: payload
  }
}];

const response = $input.first().json;
const poseData = $('Build Gemini Payload').first().json;

let imageBase64 = '';
let mimeType = 'image/png';

// Extract image from Gemini response — may contain both text and image parts
if (response.candidates && response.candidates[0]) {
  const parts = response.candidates[0].content.parts;
  for (const part of parts) {
    if (part.inlineData) {
      imageBase64 = part.inlineData.data;
      mimeType = part.inlineData.mimeType || 'image/png';
      break;
    }
  }
}

if (!imageBase64) {
  throw new Error('No image data returned from Gemini for pose ' + poseData.pose_id);
}

const orientationSlug = poseData.orientation.replace(':', 'x');
const fileExt = mimeType.includes('png') ? 'png' : 'jpg';
const filename = `bowtie-pose-${poseData.pose_id}-${orientationSlug}-${poseData.batch_name}-${poseData.timestamp}.${fileExt}`;

return [
  {
    json: {
      pose_id: poseData.pose_id,
      pose_name: poseData.pose_name,
      orientation: poseData.orientation,
      batch_name: poseData.batch_name,
      filename: filename,
      timestamp: poseData.timestamp
    },
    binary: {
      data: {
        data: imageBase64,
        mimeType: mimeType,
        fileName: filename,
        fileExtension: fileExt
      }
    }
  }
];

const allItems = $('Airtable — Log Pose').all();

const totalGenerated = allItems.length;
const poseIds = [...new Set(allItems.map(i => i.json['Pose ID'] || i.json.pose_id))];
const orientations = [...new Set(allItems.map(i => i.json['Orientation'] || i.json.orientation))];
const batchName = allItems[0]?.json['Batch Name'] || allItems[0]?.json.batch_name || 'unknown';

const summary = [
  `*BowTie Pose Generator Complete (img2img)*`,
  ``,
  `Batch: \`${batchName}\``,
  `Total images generated: *${totalGenerated}*`,
  `Poses: ${poseIds.join(', ')}`,
  `Orientations: ${orientations.join(', ')}`,
  ``,
  `Drive folder: https://drive.google.com/drive/folders/${$env.BOWTIE_GDRIVE_POSES_FOLDER_ID}`
].join('\n');

return [{ json: { summary, totalGenerated, poseIds, orientations, batchName } }];
